import{_ as a,o as t,c as i,a2 as o}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Attachments","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/attachments.md","filePath":"en/guide/attachments.md"}'),l={name:"en/guide/attachments.md"};function s(n,e,r,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="attachments" tabindex="-1">Attachments <a class="header-anchor" href="#attachments" aria-label="Permalink to &quot;Attachments&quot;">​</a></h1><p>The <strong>Attachments</strong> page centralizes all attachments from your emails, whether they&#39;re in Gmail or in your local archives.</p><hr><h2 id="two-tabs" tabindex="-1">Two Tabs <a class="header-anchor" href="#two-tabs" aria-label="Permalink to &quot;Two Tabs&quot;">​</a></h2><p>The page is divided into two tabs:</p><h3 id="archives-nas" tabindex="-1">Archives (NAS) <a class="header-anchor" href="#archives-nas" aria-label="Permalink to &quot;Archives (NAS)&quot;">​</a></h3><p>Attachments from emails archived on your NAS. They are stored separately from EML files and indexed in the database.</p><ul><li>Search by file name</li><li>Sort by size or date</li><li>Direct download</li></ul><h3 id="gmail-live" tabindex="-1">Gmail (Live) <a class="header-anchor" href="#gmail-live" aria-label="Permalink to &quot;Gmail (Live)&quot;">​</a></h3><p>Attachments from emails still in your Gmail mailbox. A scan is performed via the Gmail API to retrieve the list.</p><ul><li>On-demand scan</li><li>Sort by size to identify the largest files</li><li>Navigate to the email in Gmail</li></ul><blockquote><p>📸 <em>Suggested screenshot: Attachments page with both Archives / Gmail tabs, the attachment list, and sort buttons</em></p></blockquote><hr><h2 id="search-and-sort" tabindex="-1">Search and Sort <a class="header-anchor" href="#search-and-sort" aria-label="Permalink to &quot;Search and Sort&quot;">​</a></h2><p>You can:</p><ul><li><strong>Search</strong> by file name (e.g., <code>invoice</code>, <code>.pdf</code>, <code>photo.jpg</code>)</li><li><strong>Sort by size</strong>: largest files first — ideal for freeing up space</li><li><strong>Sort by date</strong>: newest or oldest first</li><li><strong>Paginate</strong>: navigate between result pages</li></ul><hr><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>Click the <strong>Download</strong> button next to an attachment to download it directly. Archived attachments are served from the NAS, while Gmail attachments are fetched via the Gmail API.</p><hr><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>Free up Gmail space</strong>: identify the largest attachments, archive the corresponding emails to the NAS, then delete them from Gmail</li><li><strong>Find a file</strong>: search for a file name in the archives</li><li><strong>Storage audit</strong>: visualize the distribution of attachment types</li></ul><hr><h2 id="content-hash-deduplication" tabindex="-1">Content Hash Deduplication <a class="header-anchor" href="#content-hash-deduplication" aria-label="Permalink to &quot;Content Hash Deduplication&quot;">​</a></h2><p>Nid automatically deduplicates identical attachments during archiving. Each file is identified by its SHA-256 hash: if two emails contain exactly the same attachment, the file is stored only once on disk.</p><h3 id="statistics" tabindex="-1">Statistics <a class="header-anchor" href="#statistics" aria-label="Permalink to &quot;Statistics&quot;">​</a></h3><p>The <strong>Space Saved</strong> card displays:</p><ul><li>The amount of disk space saved through deduplication</li><li>The number of duplicate files detected</li><li>Hash coverage (percentage of attachments analyzed)</li></ul><h3 id="backfill" tabindex="-1">Backfill <a class="header-anchor" href="#backfill" aria-label="Permalink to &quot;Backfill&quot;">​</a></h3><p>If you archived emails before deduplication was enabled, click the <strong>Analyze</strong> button to calculate hashes for existing attachments. This operation:</p><ol><li>Reads each file from storage (local or S3)</li><li>Calculates the SHA-256 hash</li><li>Identifies duplicates and removes redundant copies</li><li>Updates the database to point to the unique file</li></ol><blockquote><p>⚠️ Backfill may take some time if you have many archived attachments.</p></blockquote>',32)])])}const p=a(l,[["render",s]]);export{u as __pageData,p as default};
